import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function AddTest() {
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();
  const [courses, setCourses] = useState([]);
  const [title, setTitle] = useState("");
  const [courseId, setCourseId] = useState("");
  const [deadline, setDeadline] = useState("");
  const [questions, setQuestions] = useState([{ text: "", options: ["", "", "", ""], correctAnswerIndex: 0 }]);

  useEffect(() => {
    if (user?.role === "teacher") {
      fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setCourses(data))
        .catch((error) => toast.error("Ошибка загрузки курсов"));
    }
  }, [user]);

  const handleQuestionChange = (index, field, value) => {
    const newQuestions = [...questions];
    if (field === "text") {
      newQuestions[index].text = value;
    } else if (field === "correctAnswerIndex") {
      newQuestions[index].correctAnswerIndex = parseInt(value);
    } else {
      newQuestions[index].options[field] = value;
    }
    setQuestions(newQuestions);
  };

  const addQuestion = () => {
    setQuestions([...questions, { text: "", options: ["", "", "", ""], correctAnswerIndex: 0 }]);
  };

  const removeQuestion = (index) => {
    setQuestions(questions.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title || !courseId || !deadline || questions.some(q => !q.text || q.options.some(opt => !opt))) {
      toast.error("Заполните все поля!");
      return;
    }

    const newTest = {
      title,
      courseId: parseInt(courseId),
      deadline,
      questions: questions.map((q, index) => ({ ...q, id: index + 1 })),
    };

    const response = await fetch("http://localhost:3001/tests", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newTest),
    });

    if (response.ok) {
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          message: `Тест "${title}" добавлен для курса "${courses.find(c => c.id === parseInt(courseId)).name}".`,
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success("Тест успешно добавлен!");
      navigate("/courses");
    } else {
      toast.error("Не удалось добавить тест");
    }
  };

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Добавить тест</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label htmlFor="title" className="form-label">Название теста</label>
              <input
                type="text"
                id="title"
                className="form-control"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                required
              />
            </div>
            <div className="mb-3">
              <label htmlFor="courseId" className="form-label">Курс</label>
              <select
                id="courseId"
                className="form-select"
                value={courseId}
                onChange={(e) => setCourseId(e.target.value)}
                required
              >
                <option value="">-- Выберите курс --</option>
                {courses.map((course) => (
                  <option key={course.id} value={course.id}>
                    {course.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="mb-3">
              <label htmlFor="deadline" className="form-label">Дедлайн</label>
              <input
                type="datetime-local"
                id="deadline"
                className="form-control"
                value={deadline}
                onChange={(e) => setDeadline(e.target.value)}
                required
              />
            </div>
            {questions.map((question, qIndex) => (
              <div key={qIndex} className="mb-4 border p-3 rounded">
                <div className="mb-3">
                  <label className="form-label">Вопрос {qIndex + 1}</label>
                  <input
                    type="text"
                    className="form-control"
                    value={question.text}
                    onChange={(e) => handleQuestionChange(qIndex, "text", e.target.value)}
                    placeholder="Введите вопрос"
                    required
                  />
                </div>
                {question.options.map((option, oIndex) => (
                  <div key={oIndex} className="mb-2">
                    <label className="form-label">Вариант {oIndex + 1}</label>
                    <input
                      type="text"
                      className="form-control"
                      value={option}
                      onChange={(e) => handleQuestionChange(qIndex, oIndex, e.target.value)}
                      placeholder={`Вариант ${oIndex + 1}`}
                      required
                    />
                  </div>
                ))}
                <div className="mb-3">
                  <label className="form-label">Правильный ответ</label>
                  <select
                    className="form-select"
                    value={question.correctAnswerIndex}
                    onChange={(e) => handleQuestionChange(qIndex, "correctAnswerIndex", e.target.value)}
                  >
                    {question.options.map((_, index) => (
                      <option key={index} value={index}>
                        Вариант {index + 1}
                      </option>
                    ))}
                  </select>
                </div>
                {questions.length > 1 && (
                  <button type="button" className="btn btn-danger btn-sm" onClick={() => removeQuestion(qIndex)}>
                    Удалить вопрос
                  </button>
                )}
              </div>
            ))}
            <button type="button" className="btn btn-secondary mb-3" onClick={addQuestion}>
              Добавить вопрос
            </button>
            <button type="submit" className="btn btn-primary w-100">Сохранить тест</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default AddTest;
